{action_set_definitions}: {
  "get_fleet_status": {
    "description": "Retrieves the current status, location, and assigned route for specific vehicles or all vehicles in the fleet.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Optional list of vehicle IDs to query. If empty, returns status for all vehicles."
        }
      },
      "required": []
    },
    "example_output": {
      "BUS_202": {
        "route": "10 Blue Line",
        "status": "Delayed",
        "location": "Westside Hub"
      },
      "BUS_210": {
        "route": "Unassigned",
        "status": "Available",
        "location": "Central Garage"
      }
    }
  },
  "check_maintenance_holds": {
    "description": "Queries the OCC (Operations Control Center) database for administrative maintenance holds on specific vehicle records. Required before CAD/AVL updates.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The unique identifier of the vehicle to check."
        }
      },
      "required": [
        "vehicle_id"
      ]
    },
    "example_output": {
      "vehicle_id": "BUS_202",
      "has_hold": true,
      "hold_type": "Administrative/Mechanical"
    }
  },
  "resolve_maintenance_hold": {
    "description": "Resolves or clears an administrative maintenance hold on a vehicle record to allow synchronization with the CAD/AVL system.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The unique identifier of the vehicle."
        },
        "resolution_code": {
          "type": "string",
          "description": "The protocol code for clearing the hold (e.g., 'SYNC_AUTH', 'MAINT_ACK')."
        }
      },
      "required": [
        "vehicle_id",
        "resolution_code"
      ]
    },
    "example_output": {
      "success": true,
      "timestamp": "2023-10-27T10:00:00Z"
    }
  },
  "set_rtpi_visibility": {
    "description": "Configures the public-facing Real-Time Passenger Information (RTPI) feed visibility for a vehicle.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The unique identifier of the vehicle."
        },
        "suppress_countdown": {
          "type": "boolean",
          "description": "Set to true to hide the vehicle's arrival predictions from public feeds."
        }
      },
      "required": [
        "vehicle_id",
        "suppress_countdown"
      ]
    },
    "example_output": {
      "vehicle_id": "BUS_202",
      "rtpi_status": "Suppressed"
    }
  },
  "update_cad_avl_assignment": {
    "description": "Updates the Computer-Aided Dispatch/Automatic Vehicle Location (CAD/AVL) system to assign a vehicle to a specific route, direction, and schedule block.",
    "parameters": {
      "type": "object",
      "properties": {
        "vehicle_id": {
          "type": "string",
          "description": "The vehicle to be reassigned."
        },
        "target_route": {
          "type": "string",
          "description": "The route name or ID (e.g., 'Route 10 Blue Line')."
        },
        "direction": {
          "type": "string",
          "enum": [
            "Northbound",
            "Southbound",
            "Eastbound",
            "Westbound"
          ],
          "description": "The service direction."
        },
        "schedule_relationship": {
          "type": "string",
          "description": "The type of service (e.g., 'Replacement', 'Added', 'Scheduled')."
        }
      },
      "required": [
        "vehicle_id",
        "target_route",
        "direction"
      ]
    },
    "example_output": {
      "update_status": "Success",
      "active_trip_id": "TRIP_9982"
    }
  }
}
